  }
}

// ─── 드래그로 분할 패널 크기 조절 ─────────────────────────────────────────────

function initResizer() {
  resizer.addEventListener('mousedown', (e) => {
    isResizing = true;
    resizeStartX = e.clientX;
    resizeStartEditorWidth = editorPane.offsetWidth;
    resizeStartPreviewWidth = previewPane.offsetWidth;
    document.body.classList.add('is-resizing');
    e.preventDefault();
  });

  document.addEventListener('mousemove', (e) => {
    if (!isResizing) return;

    const dx = e.clientX - resizeStartX;
    const containerWidth = resizeStartEditorWidth + resizeStartPreviewWidth;
    const newEditorWidth = resizeStartEditorWidth + dx;
    const minWidth = 200;

    if (newEditorWidth < minWidth || containerWidth - newEditorWidth < minWidth) return;

    const editorPercent = (newEditorWidth / containerWidth) * 100;
    const previewPercent = 100 - editorPercent;

    editorPane.style.flex = `0 0 ${editorPercent}%`;
    previewPane.style.flex = `0 0 ${previewPercent}%`;
  });

  document.addEventListener('mouseup', () => {
    if (!isResizing) return;
    isResizing = false;
    document.body.classList.remove('is-resizing');
  });
}

// ─── HTML 내보내기 ─────────────────────────────────────────────────────────────

function exportHtml() {
  const bodyHtml = MarkdownParser.parse(editor.value);

  // 미리보기 스타일을 포함한 완전한 HTML 문서 생성
  const fullHtml = `<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>내보낸 마크다운</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      font-size: 16px;
      line-height: 1.7;
      color: #24292f;
      background: #ffffff;
      max-width: 800px;
      margin: 0 auto;
      padding: 40px 24px;
    }
    h1, h2, h3, h4, h5, h6 {
      font-weight: 600;
      line-height: 1.3;
      margin-top: 1.5em;
      margin-bottom: 0.5em;
    }
    h1 { font-size: 2em; border-bottom: 1px solid #d0d7de; padding-bottom: 0.3em; }
    h2 { font-size: 1.5em; border-bottom: 1px solid #d0d7de; padding-bottom: 0.3em; }
    h3 { font-size: 1.25em; }
    p { margin-bottom: 1em; }
    a { color: #0969da; text-decoration: none; }
    a:hover { text-decoration: underline; }
    strong { font-weight: 600; }
    em { font-style: italic; }
    code {
      font-family: 'SFMono-Regular', Consolas, monospace;
      font-size: 0.875em;
      background: #f6f8fa;
      padding: 0.2em 0.4em;
      border-radius: 4px;
      color: #e03e2f;
    }
    pre {
      background: #f6f8fa;
      border-radius: 6px;
      padding: 16px;
      overflow-x: auto;
      margin-bottom: 1em;
      position: relative;
    }
    pre code {
      background: none;
      padding: 0;
      font-size: 0.875em;
      color: #24292f;
    }
    .code-lang-label {
      font-family: monospace;
      font-size: 0.75em;
      color: #57606a;
      margin-bottom: 8px;
    }
    blockquote {
      border-left: 4px solid #d0d7de;
      padding: 0 1em;
      color: #57606a;
      margin: 0 0 1em;
    }
    ul, ol { padding-left: 2em; margin-bottom: 1em; }
    li { margin-bottom: 0.25em; }
    hr { border: none; border-top: 1px solid #d0d7de; margin: 2em 0; }
    img { max-width: 100%; height: auto; border-radius: 4px; }
    table { border-collapse: collapse; width: 100%; margin-bottom: 1em; }
    th, td { border: 1px solid #d0d7de; padding: 8px 12px; }
    th { background: #f6f8fa; font-weight: 600; }
  </style>
</head>
<body>
${bodyHtml}
</body>
</html>`;

  const blob = new Blob([fullHtml], { type: 'text/html;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'document.html';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// ─── 초기화 ───────────────────────────────────────────────────────────────────

function init() {
  editor = document.getElementById('editor');
  preview = document.getElementById('preview');
  resizer = document.getElementById('resizer');
  editorPane = document.getElementById('editor-pane');
  previewPane = document.getElementById('preview-pane');

  loadFromStorage();
  updatePreview();

  // 입력 이벤트: 미리보기 갱신 + 자동 저장
  editor.addEventListener('input', () => {
    updatePreview();
    scheduleAutoSave();
  });

  // 툴바 클릭
  document.getElementById('toolbar').addEventListener('click', handleToolbarClick);

  // 키보드 단축키
  editor.addEventListener('keydown', handleKeydown);

  // 드래그 리사이저
  initResizer();

  // 내보내기 버튼
  document.getElementById('export-btn').addEventListener('click', exportHtml);
}

document.addEventListener('DOMContentLoaded', init);

