/* ── 전역 초기화 & 커스텀 프로퍼티 ──────────────────────────────────────────── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  /* 다크 테마 색상 */
  --bg-base:       #1e1e2e;
  --bg-surface:    #24273a;
  --bg-overlay:    #2a2d3e;
  --bg-code:       #181926;
  --border:        #363a4f;
  --border-light:  #494d64;

  --text-primary:  #cad3f5;
  --text-muted:    #8087a2;
  --text-heading:  #e0e4f6;
  --text-code:     #f4dbd6;

  --accent-blue:   #8aadf4;
  --accent-green:  #a6da95;
  --accent-mauve:  #c6a0f6;
  --accent-peach:  #f5a97f;
  --accent-yellow: #eed49f;

  --resizer-bg:    #363a4f;
  --resizer-hover: #8aadf4;

  --shadow:        0 2px 8px rgba(0, 0, 0, 0.4);
  --radius-sm:     4px;
  --radius-md:     6px;
  --radius-lg:     8px;

  --font-sans: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', sans-serif;
  --font-mono: 'SFMono-Regular', 'Cascadia Code', Consolas, 'Liberation Mono', Menlo, monospace;
}

html, body {
  height: 100%;
  overflow: hidden;
  background: var(--bg-base);
  color: var(--text-primary);
  font-family: var(--font-sans);
  font-size: 14px;
  line-height: 1.6;
}

/* ── 앱 레이아웃 ──────────────────────────────────────────────────────────────── */
.app-wrapper {
  display: flex;
  flex-direction: column;
  height: 100vh;
}

/* ── 헤더 ─────────────────────────────────────────────────────────────────────── */
.app-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 16px;
  height: 48px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  box-shadow: var(--shadow);
  z-index: 10;
}

.app-title {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 15px;
  font-weight: 600;
  color: var(--text-heading);
  letter-spacing: 0.02em;
}

.app-logo {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  background: var(--accent-blue);
  color: var(--bg-base);
  border-radius: var(--radius-sm);
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 0.05em;
}

.export-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 14px;
  background: var(--accent-blue);
  color: var(--bg-base);
  border: none;
  border-radius: var(--radius-sm);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: opacity 0.15s, transform 0.1s;
}

.export-btn:hover {
  opacity: 0.88;
}

.export-btn:active {
  transform: scale(0.97);
}

.export-btn svg {
  width: 15px;
  height: 15px;
}

/* ── 툴바 ─────────────────────────────────────────────────────────────────────── */
.toolbar {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 2px;
  padding: 6px 10px;
  background: var(--bg-overlay);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.toolbar-group {
  display: flex;
  align-items: center;
  gap: 2px;
}

.toolbar-sep {
  width: 1px;
  height: 22px;
  background: var(--border-light);
  margin: 0 6px;
  flex-shrink: 0;
}

.toolbar-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 32px;
  height: 30px;
  padding: 0 8px;
  background: transparent;
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 13px;
  font-family: var(--font-sans);
  font-weight: 500;
  cursor: pointer;
  transition: background 0.12s, border-color 0.12s, color 0.12s;
  white-space: nowrap;
  user-select: none;
}

.toolbar-btn svg {
  width: 15px;
  height: 15px;
  flex-shrink: 0;
}

.toolbar-btn:hover {
  background: var(--bg-surface);
  border-color: var(--border);
  color: var(--text-heading);
}

.toolbar-btn:active {
  background: var(--border);
  transform: scale(0.95);
}

.toolbar-btn[data-action="bold"] { font-weight: 800; }
.toolbar-btn[data-action="italic"] { font-style: italic; }

/* ── 에디터 컨테이너 (분할 패널) ──────────────────────────────────────────────── */
.editor-container {
  display: flex;
  flex: 1;
  overflow: hidden;
  min-height: 0;
}

/* ── 에디터 패널 ──────────────────────────────────────────────────────────────── */
.editor-pane,
.preview-pane {
  display: flex;
  flex-direction: column;
  flex: 0 0 50%;
  min-width: 200px;
  overflow: hidden;
}

.pane-label {
  padding: 6px 14px;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

#editor {
  flex: 1;
  padding: 20px 24px;
  background: var(--bg-base);
  color: var(--text-primary);
  border: none;
  outline: none;
  resize: none;
  font-family: var(--font-mono);
  font-size: 14px;
  line-height: 1.75;
  caret-color: var(--accent-blue);
  tab-size: 2;
  overflow-y: auto;
}

#editor::placeholder {
  color: var(--text-muted);
  opacity: 0.6;
}

/* ── 리사이저 ─────────────────────────────────────────────────────────────────── */
.resizer {
  flex: 0 0 6px;
  background: var(--resizer-bg);
  cursor: col-resize;
  position: relative;
  transition: background 0.15s;
  display: flex;
  align-items: center;
  justify-content: center;
}

.resizer::after {
  content: '';
  position: absolute;
  width: 2px;
  height: 40px;
  background: var(--border-light);
  border-radius: 2px;
  transition: background 0.15s, height 0.15s;
}

.resizer:hover,
.resizer:hover::after {
  background: var(--resizer-hover);
}

.resizer:hover::after {
  height: 60px;
}

body.is-resizing {
  cursor: col-resize;
  user-select: none;
}

body.is-resizing .resizer::after {
  background: var(--accent-blue);
  height: 60px;
}

/* ── 미리보기 패널 ────────────────────────────────────────────────────────────── */
.preview-pane {
  border-left: 1px solid var(--border);
}

#preview {
  flex: 1;
  padding: 20px 28px;
  overflow-y: auto;
  color: var(--text-primary);
  line-height: 1.7;
}

/* ── 마크다운 미리보기 스타일 (GitHub 스타일 다크) ───────────────────────────── */
#preview h1,
#preview h2,
#preview h3,
#preview h4,
#preview h5,
#preview h6 {
  color: var(--text-heading);
  font-weight: 600;
  line-height: 1.3;
  margin-top: 1.6em;
  margin-bottom: 0.5em;
}

#preview h1 {
  font-size: 1.9em;
  border-bottom: 1px solid var(--border-light);
  padding-bottom: 0.35em;
}

#preview h2 {
  font-size: 1.5em;
  border-bottom: 1px solid var(--border);
  padding-bottom: 0.3em;
}

#preview h3 { font-size: 1.25em; }
#preview h4 { font-size: 1.1em; }
#preview h5 { font-size: 1em; }
#preview h6 { font-size: 0.9em; color: var(--text-muted); }

#preview p {
  margin-bottom: 0.9em;
}

#preview a {
  color: var(--accent-blue);
  text-decoration: none;
  border-bottom: 1px solid transparent;
  transition: border-color 0.15s;
}

#preview a:hover {
  border-bottom-color: var(--accent-blue);
}

#preview strong {
  font-weight: 700;
  color: var(--text-heading);
}

#preview em {
  font-style: italic;
  color: var(--accent-mauve);
}

#preview code {
  font-family: var(--font-mono);
  font-size: 0.865em;
  background: var(--bg-code);
  color: var(--text-code);
  padding: 0.15em 0.45em;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
}

/* 코드 블록 */
#preview pre.code-block {
  position: relative;
  background: var(--bg-code);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  margin-bottom: 1em;
  overflow: hidden;
}

#preview pre.code-block .code-lang-label {
  display: block;
  padding: 5px 14px;
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: var(--accent-yellow);
  background: rgba(0, 0, 0, 0.2);
  border-bottom: 1px solid var(--border);
}

#preview pre.code-block code {
  display: block;
  padding: 16px;
  background: none;
  border: none;
  border-radius: 0;
  font-size: 13px;
  color: var(--text-primary);
  overflow-x: auto;
  white-space: pre;
  line-height: 1.65;
}

/* 인용 블록 */
#preview blockquote {
  border-left: 4px solid var(--accent-blue);
  margin: 0 0 1em;
  padding: 4px 16px;
  color: var(--text-muted);
  background: rgba(138, 173, 244, 0.06);
  border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
}

#preview blockquote > * {
  color: var(--text-muted);
}

#preview blockquote blockquote {
  border-left-color: var(--accent-mauve);
  background: rgba(198, 160, 246, 0.05);
  margin-top: 0.5em;
}

/* 리스트 */
#preview ul,
#preview ol {
  padding-left: 1.8em;
  margin-bottom: 0.9em;
}

#preview li {
  margin-bottom: 0.2em;
  line-height: 1.65;
}

#preview li > ul,
#preview li > ol {
  margin-top: 0.25em;
  margin-bottom: 0.25em;
}

#preview ul { list-style-type: disc; }
#preview ul ul { list-style-type: circle; }
#preview ul ul ul { list-style-type: square; }

/* 수평선 */
#preview hr {
  border: none;
  border-top: 2px solid var(--border-light);
  margin: 1.8em 0;
}

/* 이미지 */
#preview img {
  max-width: 100%;
  height: auto;
  border-radius: var(--radius-md);
  border: 1px solid var(--border);
  margin: 0.5em 0;
}

/* ── 스크롤바 스타일링 ────────────────────────────────────────────────────────── */
#editor::-webkit-scrollbar,
#preview::-webkit-scrollbar {
  width: 8px;
}

#editor::-webkit-scrollbar-track,
#preview::-webkit-scrollbar-track {
  background: transparent;
}

#editor::-webkit-scrollbar-thumb,
#preview::-webkit-scrollbar-thumb {
  background: var(--border-light);
  border-radius: 4px;
}

#editor::-webkit-scrollbar-thumb:hover,
#preview::-webkit-scrollbar-thumb:hover {
  background: var(--text-muted);
}

/* ── 반응형: 모바일에서 세로 분할 ─────────────────────────────────────────────── */
@media (max-width: 720px) {
  .editor-container {
    flex-direction: column;
  }

  .editor-pane,
  .preview-pane {
    flex: 0 0 50% !important;
    min-width: unset;
    min-height: 200px;
  }

  .resizer {
    flex: 0 0 6px;
    width: 100%;
    cursor: row-resize;
    border-left: none;
    border-top: 1px solid var(--border);
  }

  .resizer::after {
    width: 40px;
    height: 2px;
  }

  .preview-pane {
    border-left: none;
    border-top: 1px solid var(--border);
  }
}

@media (max-width: 480px) {
  .app-title span:last-child { display: none; }
  .export-btn span { display: none; }
  .toolbar { gap: 1px; }
  .toolbar-btn { min-width: 28px; height: 26px; font-size: 12px; }
}

