  assertContains   (p('[link](url) **bold**'),  '<a ',                   'Link then bold (link present)');
  assertContains   (p('[link](url) **bold**'),  '<strong>bold</strong>', 'Link then bold (bold present)');
});

// ─── 16. Toolbar Actions ─────────────────────────────────────────────────────
describe('Toolbar: Bold', () => {
  setEditorState('', 0, 0);
  clickToolbar('bold');
