   309→      TOOLBAR_ACTIONS.italic();
   310→      break;
   311→    case 'k':
   312→      e.preventDefault();
   313→      TOOLBAR_ACTIONS.link();
   314→      break;
   315→    default:
   316→      break;
   317→  }
   318→}
   319→
   320→// ─── 드래그로 분할 패널 크기 조절 ─────────────────────────────────────────────
   321→
   322→function initResizer() {
   323→  resizer.addEventListener('mousedown', (e) => {
   324→    isResizing = true;
   325→    resizeStartX = e.clientX;
   326→    resizeStartEditorWidth = editorPane.offsetWidth;
   327→    resizeStartPreviewWidth = previewPane.offsetWidth;
   328→    document.body.classList.add('is-resizing');
