    }
    pre {
      background: #f6f8fa;
      border-radius: 6px;
      padding: 16px;
      overflow-x: auto;
      margin-bottom: 1em;
      position: relative;
    }
    pre code {
      background: none;
      padding: 0;
      font-size: 0.875em;
      color: #24292f;
    }
    .code-lang-label {
      font-family: monospace;
