  assertContains(ul, '<ul>',           'UL opening tag');
  assertContains(ul, '</ul>',          'UL closing tag');
  assertContains(ul, '<li>one</li>',   'UL item 1');
  assertContains(ul, '<li>two</li>',   'UL item 2');
  assertContains(ul, '<li>three</li>', 'UL item 3');
