describe('Parser: Escape Characters', () => {
  assertNotContains(p('\\*not italic\\*'),   '<em>',     'Escaped * is not italic');
  assertContains   (p('\\*not italic\\*'),   '*',        'Escaped * renders as literal asterisk');
